B.PP=new A.an("Wisdom needs nourishment. Read or listen to something that challenges your worldview today.","\u041c\u0443\u0434\u0440\u043e\u0441\u0442\u044c \u043d\u0443\u0436\u0434\u0430\u0435\u0442\u0441\u044f \u0432 \u043f\u0438\u0442\u0430\u043d\u0438\u0438. \u041f\u0440\u043e\u0447\u0442\u0438 \u0438\u043b\u0438 \u043f\u043e\u0441\u043b\u0443\u0448\u0430\u0439 \u0442\u043e, \u0447\u0442\u043e \u0431\u0440\u043e\u0441\u0430\u0435\u0442 \u0432\u044b\u0437\u043e\u0432 \u0442\u0432\u043e\u0435\u043c\u0443 \u043c\u0438\u0440\u043e\u0432\u043e\u0437\u0437\u0440\u0435\u043d\u0438\u044e.","weakest_2",null)
