B.PS=new A.an("Chesed is calling: perform one act of unconditional kindness today.","\u0425\u0435\u0441\u0435\u0434 \u0437\u043e\u0432\u0451\u0442: \u0441\u043e\u0432\u0435\u0440\u0448\u0438 \u043e\u0434\u0438\u043d \u0430\u043a\u0442 \u0431\u0435\u0437\u0443\u0441\u043b\u043e\u0432\u043d\u043e\u0439 \u0434\u043e\u0431\u0440\u043e\u0442\u044b \u0441\u0435\u0433\u043e\u0434\u043d\u044f.","weakest_5",null)
